// The node reports failures explicitly rather than going silent, so a
// message with ok:false means the ESP is alive and the probe is not.
// That's a different repair job from no messages at all.
if (msg.payload.ok === false) {
    node.status({ fill: "red", shape: "ring", text: "probe fault: " + msg.payload.error });
    return null;
}

const mm = msg.payload.depth_mm;
let text = mm + " mm";
if (msg.payload.percent !== undefined) text += "  (" + msg.payload.percent + "%)";

node.status({ fill: "green", shape: "dot", text: text });
return { payload: mm, topic: msg.payload.node };
